for (uint256 i; i < users.length; ++i) {
    WithdrawRequest storage request = userWithdrawRequest[users[i]][share];

    if (request.inSolve) {
        // We know that the minimum price and deadline arguments are satisfied since this can only be true if they were.

        // Send user their share of assets.
        uint256 assetsToUser = _calculateAssetAmount(
            request.sharesToWithdraw,
            request.executionSharePrice,
            solveData.shareDecimals
        );

        solveData.asset.safeTransferFrom(solver, users[i], assetsToUser);

        emit RequestFulfilled(
            users[i],
            address(share),
            request.sharesToWithdraw,
            assetsToUser,
            block.timestamp
        );

        // Set shares to withdraw to 0.
        request.sharesToWithdraw = 0;
        request.inSolve = false;
    } else revert WithdrawQueue__UserNotInSolve(users[i]);
}

while (
    (block.number - currentMaintenanceStakerStartBlock) *
        maintenanceStakePerBlock >=
    currentStake
) {
    if (maintenanceStakePerBlock > currentStake) {
        // delete current from daisy chain
        address nextOne =
            nextMaintenanceStaker[currentMaintenanceStaker];
        nextMaintenanceStaker[prevMaintenanceStaker] = nextOne;
        nextMaintenanceStaker[currentMaintenanceStaker] = address(0);

        currentMaintenanceStaker = nextOne;
    } else {
        currentMaintenanceStakerStartBlock +=
            currentStake /
            maintenanceStakePerBlock;

        prevMaintenanceStaker = currentMaintenanceStaker;
        currentMaintenanceStaker = nextMaintenanceStaker[
            currentMaintenanceStaker
        ];
    }
    currentStake = getMaintenanceStakerStake(currentMaintenanceStaker);
}

try priceAggregator.latestRoundData() returns
        (
            uint80 roundId,
            int256 answer,
            uint256 /* startedAt */,
            uint256 timestamp,
            uint80 /* answeredInRound */
        )
        {
            // If call to Chainlink succeeds, return the response and success = true
            chainlinkResponse.roundId = roundId;
            chainlinkResponse.answer = answer;
            chainlinkResponse.timestamp = timestamp;
            chainlinkResponse.success = true;
            return chainlinkResponse;
        } catch {
            // If call to Chainlink aggregator reverts, return a zero response with success = false
            return chainlinkResponse;
        }

for (vars.i = 0; vars.i < troveArrayLen; ++vars.i) {
    vars.user = _troveArray[vars.i];
    vars.ICR = troveManager.getCurrentICR(vars.user);
    if (vars.ICR < MCR) {
        singleLiquidation = _liquidateNormalMode(
            _activePool,
            _defaultPool,
            vars.user,
            vars.remainingYUSDInStabPool
        );
        vars.remainingYUSDInStabPool = vars.remainingYUSDInStabPool.sub(
            singleLiquidation.debtToOffset
        );

        // If wrapped assets exist then update the reward to this contract temporarily
        _updateWAssetsRewardOwner(singleLiquidation.collGasCompensation, vars.user, address(this));

        // Add liquidation values to their respective running totals
        totals = _addLiquidationValuesToTotals(totals, singleLiquidation);
    }
}

(vars.userVariableDebt, vars.userTotalDebt, vars.actualDebtToLiquidate) = _calculateDebt(
      vars.debtReserveCache,
      params,
      vars.healthFactor
    );

    ValidationLogic.validateLiquidationCall(
      userConfig,
      collateralReserve,
      DataTypes.ValidateLiquidationCallParams({
        debtReserveCache: vars.debtReserveCache,
        totalDebt: vars.userTotalDebt,
        healthFactor: vars.healthFactor,
        priceOracleSentinel: params.priceOracleSentinel
      })
    );

    (
      vars.collateralAToken,
      vars.collateralPriceSource,
      vars.debtPriceSource,
      vars.liquidationBonus
    ) = _getConfigurationData(eModeCategories, collateralReserve, params);

    vars.userCollateralBalance = vars.collateralAToken.balanceOf(params.user);

if(interestRedirectionAddresses[_user] == address(0)){

    //accruing for himself means that both the principal balance and
    //the redirected balance partecipate in the interest
    return calculateCumulatedBalanceInternal(
        _user,
        currentPrincipalBalance.add(redirectedBalance)
    )
    .sub(redirectedBalance);
}
else {
    //if the user redirected the interest, then only the redirected
    //balance generates interest. In that case, the interest generated
    //by the redirected balance is added to the current principal balance.
    return currentPrincipalBalance.add(
        calculateCumulatedBalanceInternal(
            _user,
            redirectedBalance
        )
        .sub(redirectedBalance)
    );
}
